	// Make the given context the active one (sets activation_time = now).
	// Used for reactivating older contexts and forking from archived branches.
	ActivateContext(context.Context, *connect.Request[v1.ActivateContextRequest]) (*connect.Response[v1.ActivateContextResponse], error)
	// Move the per-context "currently viewing" cursor to a specific message.
	// Used by branch navigation: after a user picks an alternate child fork,
	// the client calls this to update the server-side leaf so the next
	// SendMessage parents off the chosen branch.
	SetCurrentLeaf(context.Context, *connect.Request[v1.SetCurrentLeafRequest]) (*connect.Response[v1.SetCurrentLeafResponse], error)
